package com.nutrisense.entity;
import jakarta.persistence.*; import lombok.*; import java.math.*; import java.time.*;
@Getter @Setter @Builder @NoArgsConstructor @AllArgsConstructor @Entity @Table(name="body_measurements") public class BodyMeasurement { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="progress_log_id",nullable=false) private ProgressLog progressLog; @Column(name="chest_cm",precision=5,scale=2) private BigDecimal chestCm; @Column(name="waist_cm",precision=5,scale=2) private BigDecimal waistCm; @Column(name="hip_cm",precision=5,scale=2) private BigDecimal hipCm; @Column(name="biceps_cm",precision=5,scale=2) private BigDecimal bicepsCm; @Column(name="thigh_cm",precision=5,scale=2) private BigDecimal thighCm; @Column(name="neck_cm",precision=5,scale=2) private BigDecimal neckCm; @Column(name="created_at",insertable=false,updatable=false) private Instant createdAt; }
